SELECT w.order_id, w.cl_order_id, w.created_at AS createdAt, w.updated_at AS updatedAt, c.cl_delivery_date AS dueDate, w.line_id, l.line_name, w.product_id, p.product_name, w.order_qty, w.priority, w.is_followup AS isFollowup, w.status, c.client_id, cl.client_name AS clientName, c.cl_order_date AS clOrderDate FROM work_order w LEFT JOIN production_line l ON w.line_id = l.line_id LEFT JOIN product p ON w.product_id = p.product_id LEFT JOIN client_order c ON w.cl_order_id = c.cl_order_id LEFT JOIN client cl ON c.client_id = cl.client_id
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR w.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR cl.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}
ORDER BY
CASE w.priority WHEN 'EMERGENCY' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'NORMAL' THEN 3 WHEN 'LOW' THEN 4 ELSE 5 END ${sortOrder}
${sortColumn} ${sortOrder}
w.created_at DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM work_order w LEFT JOIN product p ON w.product_id = p.product_id LEFT JOIN client_order c ON w.cl_order_id = c.cl_order_id LEFT JOIN client cl ON c.client_id = cl.client_id
AND ( w.order_id LIKE CONCAT('%', #{keyword}, '%') OR w.cl_order_id LIKE CONCAT('%', #{keyword}, '%') OR p.product_name LIKE CONCAT('%', #{keyword}, '%') OR cl.client_name LIKE CONCAT('%', #{keyword}, '%') )
AND w.status = #{status}
AND DATE(w.created_at) >= #{startDate}
AND DATE(w.created_at) <= #{endDate}
